import{_ as s,o as n,c as e,ae as l}from"./chunks/framework.DL_9NXHq.js";const u=JSON.parse('{"title":"Claude Skill 优化","description":"","frontmatter":{},"headers":[],"relativePath":"AI/Claude Skill 优化.md","filePath":"AI/Claude Skill 优化.md"}'),p={name:"AI/Claude Skill 优化.md"};function t(i,a,r,c,d,o){return n(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="claude-skill-优化" tabindex="-1">Claude Skill 优化 <a class="header-anchor" href="#claude-skill-优化" aria-label="Permalink to &quot;Claude Skill 优化&quot;">​</a></h1><p>最近使用 Claude 为自身工作流开发多个 Skill 时，实践中发现一个问题：Skill 写得越详细，响应质量反而越差。排查后发现，根本原因是自己一直用编写文档的思路编写 Skill。</p><p>实际上，编写 Skill 和编写文档是两种截然不同的思维模式：</p><ul><li>文档：面向人类阅读，追求详尽全面。</li><li>Skill：面向 AI Agent 执行，追求精简明确。</li></ul><p>关键区别在于：人类可以自主选择性阅读文档，信息冗余有益无害；但 AI Agent 的上下文窗口是共享资源，每一个字符都有成本，加载冗余内容反而降低核心指令的权重。</p><h2 id="skill-简介" tabindex="-1">Skill 简介 <a class="header-anchor" href="#skill-简介" aria-label="Permalink to &quot;Skill 简介&quot;">​</a></h2><h3 id="skill-格式" tabindex="-1">Skill 格式 <a class="header-anchor" href="#skill-格式" aria-label="Permalink to &quot;Skill 格式&quot;">​</a></h3><p>每个 Skill 均以独立目录形式存在，包含以下文件：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/skill-name/</span></span>
<span class="line"><span>├── SKILL.md # 核心指令</span></span>
<span class="line"><span>├── scripts/ # 可执行脚本</span></span>
<span class="line"><span>├── references/ # 参考文档</span></span>
<span class="line"><span>└── assets/ # 模板文件、图片等</span></span></code></pre></div><h3 id="渐进式披露-progressive-disclosure" tabindex="-1">渐进式披露 (Progressive Disclosure) <a class="header-anchor" href="#渐进式披露-progressive-disclosure" aria-label="Permalink to &quot;渐进式披露 (Progressive Disclosure)&quot;">​</a></h3><p>Claude 针对 Skill 的加载采用分层加载、按需调用的渐进式披露机制，核心目标是节省上下文 token、提升响应效率。</p><ul><li>metadata 常驻上下文：对话启动时，Claude 会将所有 Skill 的 metadata 加载并常驻在上下文中，用于快速识别 Skill。</li><li>SKILL.md 按需加载：当用户的请求内容命中某个 Skill 时，Claude 会将该 Skill 对应的 SKILL.md 正文加载到上下文，以加载当前任务所需的核心指令。</li><li>references/ 文件按需读取：references/ 文件夹下的参考文档不会自动加载到上下文，仅当 Agent 在执行的过程中需要补充参考信息时，才会读取对应文件。</li></ul><h2 id="优化前的-skill" tabindex="-1">优化前的 Skill <a class="header-anchor" href="#优化前的-skill" aria-label="Permalink to &quot;优化前的 Skill&quot;">​</a></h2><p>以下为优化前的 <code>create-merge-request</code> Skill，通过 <a href="https://platform.openai.com/tokenizer" target="_blank" rel="noreferrer">OpenAI Tokenizer</a>（GPT-5.x 标准）统计，包含 702 字符、311 token，存在信息冗余、重点不突出的问题。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: create-merge-request</span></span>
<span class="line"><span>description: 创建 GitLab 合并请求。在创建 GitLab 合并请求(MR) 时使用。</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 创建合并请求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>自动创建 GitLab 合并请求,包含智能目标分支选择和 AI 生成的描述。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 要求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 需要安装并配置 glab CLI 工具</span></span>
<span class="line"><span>2. 需要配置 ANTHROPIC_BASE_URL 和 ANTHROPIC_AUTH_TOKEN 环境变量</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 执行步骤</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 运行 create-merge-request 脚本创建合并请求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   **使用方法:**</span></span>
<span class="line"><span>   \`\`\`bash</span></span>
<span class="line"><span>   bun run .claude/skills/create-merge-request/scripts/create-merge-request.ts</span></span>
<span class="line"><span>   \`\`\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   **功能:**</span></span>
<span class="line"><span>   - 自动确定目标分支（最新的 release/x.x.x 分支）</span></span>
<span class="line"><span>   - 比较当前分支与目标分支的代码改动</span></span>
<span class="line"><span>   - 使用 AI 生成合并请求的标题和描述</span></span>
<span class="line"><span>   - 使用 glab CLI 创建合并请求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   **环境变量要求:**</span></span>
<span class="line"><span>   - \`ANTHROPIC_BASE_URL\`: Anthropic API 的 base URL</span></span>
<span class="line"><span>   - \`ANTHROPIC_AUTH_TOKEN\`: Anthropic API 的认证 token</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 注意事项</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- 确保当前分支的改动已经提交</span></span>
<span class="line"><span>- 确保 glab 已经配置好 GitLab 访问权限</span></span>
<span class="line"><span>- 脚本会自动生成合并请求的标题和描述,无需手动输入</span></span></code></pre></div><h2 id="skill-优化原则" tabindex="-1">Skill 优化原则 <a class="header-anchor" href="#skill-优化原则" aria-label="Permalink to &quot;Skill 优化原则&quot;">​</a></h2><h3 id="agent-思考-脚本执行" tabindex="-1">Agent 思考，脚本执行 <a class="header-anchor" href="#agent-思考-脚本执行" aria-label="Permalink to &quot;Agent 思考，脚本执行&quot;">​</a></h3><p>根据任务特性，可以划分为不同的自由度等级：</p><ul><li>高自由度：多种方法均有效，决策结果需结合具体上下文判断，适合 Agent 自主决策。</li><li>中自由度：存在明确首选执行模式，同时允许少量合理变化，Agent 可在首选模式基础上灵活调整。</li><li>低自由度：操作流程脆弱、易出错，或对执行一致性要求极高，需严格按固定逻辑执行，避免偏差。</li></ul><p>针对低自由度及关键任务，使用脚本执行可解决 Agent 直接执行的痛点，核心优势有四点：</p><ul><li>不确定性收敛：大模型输出基于概率采样，存在细微差异（比如同样提示词可能用 npm 或 yarn 安装依赖），这种不确定性在关键路径上容易引发隐患，而脚本执行流程固定，避免偏差。</li><li>Token 消耗减少：脚本执行过程不消耗 token，仅在 Agent 处理文本、判断决策时消耗 token，有效降低上下文成本。</li><li>逻辑复用更高效：脚本可直接调用其他脚本，无需额外权限请求；而 Skill 之间相互调用时，大模型经常需要请求权限，增加执行步骤和耗时。</li><li>方便调试：脚本可独立运行，加日志，加单元测试，无需依赖 Agent 环境即可排查问题。</li></ul><h3 id="渐进式披露" tabindex="-1">渐进式披露 <a class="header-anchor" href="#渐进式披露" aria-label="Permalink to &quot;渐进式披露&quot;">​</a></h3><p>Claude 的<a href="https://platform.claude.com/docs/en/agents-and-tools/agent-skills/best-practices" target="_blank" rel="noreferrer">技能编写最佳实践</a>核心思想可以总结成一句话：</p><blockquote><p>默认假设：Claude 已经非常聪明。只添加 Claude 不知道的上下文。</p><p>Default assumption: Claude is already very smart. Only add context Claude doesn&#39;t already have.</p></blockquote><p>新增任何信息前，都要问自己：</p><ul><li>“这条信息 Claude 不查看这里也知道吗？”——若是，直接删除。</li><li>“这个内容只在某些场景下才会遇到吗？”——若是，移至 <code>references/</code>。</li><li>“这是步骤还是背景？”——若是背景，移至 <code>references/</code>；若是步骤，保留在 <code>SKILL.md</code>；。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SKILL.md（&lt; 500 行）：</span></span>
<span class="line"><span>  ✅ 核心工作流（每次执行都需要的步骤）</span></span>
<span class="line"><span>  ✅ 关键命令（带最常用参数）</span></span>
<span class="line"><span>  ✅ 安全边界（必须注意的约束）</span></span>
<span class="line"><span>  ❌ 常见问题</span></span>
<span class="line"><span>  ❌ 常见场景举例</span></span>
<span class="line"><span>  ❌ 细节参数说明</span></span>
<span class="line"><span></span></span>
<span class="line"><span>references/（按需加载）：</span></span>
<span class="line"><span>  ✅ 参数详细说明</span></span>
<span class="line"><span>  ✅ 常见问题与最佳实践</span></span>
<span class="line"><span>  ✅ 故障排查</span></span></code></pre></div><p>可以看到，优化前的 Skill 存在以下问题：</p><table tabindex="0"><thead><tr><th>问题类型</th><th>具体表现</th><th>优化方式</th></tr></thead><tbody><tr><td>冗余描述</td><td>对脚本功能逐条列举，Agent 执行时无需知晓脚本内部功能细节</td><td>删除</td></tr><tr><td>信息重复</td><td>在“要求”中已提及 glab CLI 和环境变量，又在“执行步骤”中重申</td><td>删除重复内容</td></tr><tr><td>防御性写作</td><td>“注意事项”本质是面向人类的提醒，Agent 无需常驻上下文</td><td>删除或移至 references/</td></tr><tr><td>背景信息</td><td>“智能目标分支选择和 AI 生成的描述”属于背景性内容，非核心步骤</td><td>移至 references/</td></tr></tbody></table><h2 id="优化后的-skill" tabindex="-1">优化后的 Skill <a class="header-anchor" href="#优化后的-skill" aria-label="Permalink to &quot;优化后的 Skill&quot;">​</a></h2><p>优化后的 Skill 精简明确，通过 <a href="https://platform.openai.com/tokenizer" target="_blank" rel="noreferrer">OpenAI Tokenizer</a>（GPT-5.x 标准）统计，包含 194 字符、71 token。</p><table tabindex="0"><thead><tr><th>指标</th><th>优化前</th><th>优化后</th><th>变化</th></tr></thead><tbody><tr><td>字符数</td><td>702</td><td>194</td><td>-72%</td></tr><tr><td>Token 数</td><td>311</td><td>71</td><td>-77%</td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: create-merge-request</span></span>
<span class="line"><span>description: 创建 GitLab 合并请求。在创建 GitLab 合并请求(MR) 时使用。</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 创建合并请求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>运行以下的脚本：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\`\`bash</span></span>
<span class="line"><span>bun run .claude/scripts/workflow/create-merge-request.ts</span></span>
<span class="line"><span>\`\`\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不要修改命令或添加额外参数。</span></span></code></pre></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>编写 Skill 的核心思路可归纳为三点：</p><ul><li>精简优于详尽：只保留 Agent 不知道的上下文，删除 Claude 已经掌握的知识。</li><li>脚本优于指令：低自由度及关键任务应封装为脚本，由脚本固定执行流程，而非让 Agent 通过自然语言指令逐步推理执行，从而减少不确定性并降低 token 消耗。</li><li>分层优于平铺：利用渐进式披露机制，将核心步骤放在 SKILL.md 常驻上下文，将背景知识、参数说明、故障排查等内容移至 references/ 按需加载。</li></ul>`,36)])])}const k=s(p,[["render",t]]);export{u as __pageData,k as default};
